<?php

// Generated by make_tool. Improved by agent: cross-platform path handling.

$toolDefinition_notes_get = array (
  'type' => 'function',
  'function' => 
  array (
    'name' => 'notes_get',
    'description' => 'Retrieve a previously stored note by key from the agent\'s workspace.',
    'parameters' => 
    array (
      'type' => 'object',
      'properties' => 
      array (
        'key' => 
        array (
          'type' => 'string',
          'description' => 'The key of the note to retrieve',
        ),
      ),
      'required' => 
      array (
        0 => 'key',
      ),
    ),
  ),
);

if (! function_exists('notes_get')) {
    function notes_get($key)
    {
        $key = trim(str_replace('\\', '/', $key), '/');
        if (!preg_match('/^[a-zA-Z0-9_\-\.\/]+$/', $key)) {
            return json_encode(['error' => 'Invalid key format']);
        }
        $notesDir = realpath(__DIR__ . '/../../workspace/notes');
        if ($notesDir === false) {
            return json_encode(['error' => 'Notes directory not found', 'key' => $key]);
        }
        $filePath = $notesDir . '/' . $key . '.note';
        if (!is_file($filePath)) {
            return json_encode(['error' => 'Note not found', 'key' => $key]);
        }
        $content = file_get_contents($filePath);
        return json_encode(['key' => $key, 'value' => $content, 'size' => strlen($content)]);
    }
}
